  1→import { useEffect } from "react";
  2→import { useLocation } from "react-router-dom";
  3→import {
  4→  DEFAULT_OG_IMAGE,
  5→  DEFAULT_OG_IMAGE_HEIGHT,
  6→  DEFAULT_OG_IMAGE_WIDTH,
  7→  ORGANIZATION_SCHEMA,
  8→  buildAbsoluteUrl,
  9→  buildWebsiteSchema,
 10→  getSeoForPath,
 11→} from "./seoConfig.js";
 12→
 13→const ensureMeta = (id, attribute, key, content) => {
 14→  let element = document.getElementById(id);
 15→  if (!element) {
 16→    element = document.createElement("meta");
 17→    element.id = id;
 18→    document.head.appendChild(element);
 19→  }
 20→
 21→  element.setAttribute(attribute, key);
 22→  element.setAttribute("content", content);
 23→};
 24→
 25→const removeElementById = (id) => {
 26→  const element = document.getElementById(id);
 27→  if (element && element.parentNode) {
 28→    element.parentNode.removeChild(element);
 29→  }
 30→};
 31→
 32→const ensureLink = (id, rel, href, extra = {}) => {
 33→  let element = document.getElementById(id);
 34→  if (!element) {
 35→    element = document.createElement("link");
 36→    element.id = id;
 37→    document.head.appendChild(element);
 38→  }
 39→
 40→  element.setAttribute("rel", rel);
 41→  element.setAttribute("href", href);
 42→  Object.entries(extra).forEach(([name, value]) => {
 43→    element.setAttribute(name, value);
 44→  });
 45→};
 46→
 47→const ensureJsonLd = (id, payload) => {
 48→  let element = document.getElementById(id);
 49→  if (!element) {
 50→    element = document.createElement("script");
 51→    element.id = id;
 52→    element.type = "application/ld+json";
 53→    document.head.appendChild(element);
 54→  }
 55→
 56→  element.textContent = JSON.stringify(payload);
 57→};
 58→
 59→const SeoManager = () => {
 60→  const { pathname } = useLocation();
 61→
 62→  useEffect(() => {
 63→    const seo = getSeoForPath(pathname);
 64→    const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
 65→    const ogTitle = seo.ogTitle || seo.title;
 66→    const ogDescription = seo.ogDescription || seo.description;
 67→    const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
 68→    const fbAppId = (import.meta.env.VITE_FB_APP_ID || "").trim();
 69→
 70→    document.title = seo.title;
 71→
 72→    ensureMeta("seo-description", "name", "description", seo.description);
 73→    ensureMeta("seo-robots", "name", "robots", seo.robots || "index,follow");
 74→
 75→    ensureMeta("seo-og-type", "property", "og:type", "website");
 76→    ensureMeta("seo-og-url", "property", "og:url", canonicalUrl);
 77→    ensureMeta("seo-og-title", "property", "og:title", ogTitle);
 78→    ensureMeta("seo-og-description", "property", "og:description", ogDescription);
 79→    ensureMeta("seo-og-image", "property", "og:image", ogImage);
 80→    ensureMeta("seo-og-image-width", "property", "og:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
 81→    ensureMeta("seo-og-image-height", "property", "og:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));
 82→    ensureMeta("seo-og-site-name", "property", "og:site_name", "Iskryb");
 83→    if (fbAppId) {
 84→      ensureMeta("seo-fb-app-id", "property", "fb:app_id", fbAppId);
 85→    } else {
 86→      removeElementById("seo-fb-app-id");
 87→    }
 88→
 89→    ensureMeta("seo-twitter-card", "name", "twitter:card", "summary_large_image");
 90→    ensureMeta("seo-twitter-title", "name", "twitter:title", ogTitle);
 91→    ensureMeta("seo-twitter-description", "name", "twitter:description", ogDescription);
 92→    ensureMeta("seo-twitter-image", "name", "twitter:image", ogImage);
 93→    ensureMeta("seo-twitter-image-width", "name", "twitter:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
 94→    ensureMeta("seo-twitter-image-height", "name", "twitter:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));
 95→
 96→    ensureLink("seo-canonical", "canonical", canonicalUrl);
 97→    ensureLink("seo-hreflang-en", "alternate", canonicalUrl, { hreflang: "en-US" });
 98→    ensureLink("seo-hreflang-default", "alternate", canonicalUrl, {
 99→      hreflang: "x-default",
100→    });
101→
102→    ensureJsonLd("seo-ld-website", buildWebsiteSchema(canonicalUrl));
103→    ensureJsonLd("seo-ld-organization", ORGANIZATION_SCHEMA);
104→  }, [pathname]);
105→
106→  return null;
107→};
108→
109→export default SeoManager;
