 1→import fs from "node:fs/promises";
 2→import path from "node:path";
 3→import {
 4→  buildAbsoluteUrl,
 5→  getSitemapRoutes,
 6→} from "../src/seo/seoConfig.js";
 7→
 8→const today = new Date().toISOString().slice(0, 10);
 9→const routes = getSitemapRoutes();
10→
11→const urlEntries = routes
12→  .map((route) => {
13→    const loc = buildAbsoluteUrl(route.path);
14→    const changefreq = route.changefreq || "weekly";
15→    const priority = route.priority || "0.5";
16→    const lastmod = route.lastmod || today;
17→
18→    return `  <url>
19→    <loc>${loc}</loc>
20→    <lastmod>${lastmod}</lastmod>
21→    <changefreq>${changefreq}</changefreq>
22→    <priority>${priority}</priority>
23→  </url>`;
24→  })
25→  .join("\n");
26→
27→const sitemap = `<?xml version="1.0" encoding="UTF-8"?>
28→<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
29→${urlEntries}
30→</urlset>
31→`;
32→
33→const outputPath = path.resolve(process.cwd(), "public", "sitemap.xml");
34→await fs.writeFile(outputPath, sitemap, "utf8");
35→
36→console.log(`Generated sitemap: ${outputPath}`);
