226→const isPrivateIpv4Address = (ip) => {
227→    const parts = ip.split('.').map((part) => Number(part));
228→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
229→        return true;
230→    }
231→
232→    const [a, b] = parts;
233→    if (a === 10 || a === 127 || a === 0) return true;
234→    if (a === 169 && b === 254) return true;
235→    if (a === 172 && b >= 16 && b <= 31) return true;
236→    if (a === 192 && b === 168) return true;
237→    return false;
238→};
239→
240→const isPrivateIpv6Address = (ip) => {
241→    const normalized = ip.toLowerCase();
242→    return (
243→        normalized === '::1' ||
244→        normalized.startsWith('fc') ||
245→        normalized.startsWith('fd') ||
246→        normalized.startsWith('fe80:')
247→    );
248→};
249→
250→const isPrivateIpAddress = (ip) => {
251→    const ipVersion = net.isIP(ip);
252→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
253→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
254→    return true;
255→};
256→
257→const isSafeRemoteImageUrl = (imageUrl) => {
258→    try {
259→        const parsed = new URL(imageUrl);
260→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
261→            return false;
262→        }
263→
264→        const hostname = parsed.hostname.toLowerCase();
265→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
266→            return false;
267→        }
268→
269→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
270→            return false;
271→        }
272→
273→        return true;
274→    } catch {
275→        return false;
276→    }
277→};
278→
279→const evaluateShareImageCandidate = (rawUrl) => {
280→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
281→    if (!absoluteUrl) {
282→        return {
283→            ok: false,
284→            reason: 'invalid_or_non_http_url',
285→            resolvedUrl: null,
286→        };
287→    }
288→
289→    let path = '';
290→    try {
291→        const parsed = new URL(absoluteUrl);
292→        path = String(parsed.pathname || '').toLowerCase();
293→    } catch {
294→        return {
295→            ok: false,
296→            reason: 'invalid_resolved_url',
297→            resolvedUrl: null,
298→        };
299→    }
300→
301→    if (path.endsWith('.svg')) {
302→        return {
303→            ok: false,
304→            reason: 'svg_not_supported_for_share_image',
305→            resolvedUrl: absoluteUrl,
306→        };
307→    }
308→
309→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
310→        return {
311→            ok: false,
312→            reason: 'unsafe_remote_url',
313→            resolvedUrl: absoluteUrl,
314→        };
315→    }
316→
317→    return {
318→        ok: true,
319→        reason: 'ok',
320→        resolvedUrl: absoluteUrl,
321→    };
322→};
323→
324→const fetchRemoteImageBuffer = async (imageUrl) => {
325→    const controller = new AbortController();
326→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
327→
328→    try {
329→        const response = await fetch(imageUrl, {
330→            method: 'GET',
331→            redirect: 'follow',
332→            signal: controller.signal,
333→            headers: {
334→                Accept: 'image/*,*/*;q=0.8',
335→                'Accept-Encoding': 'identity',
336→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
337→            },
338→        });
339→
340→        if (!response.ok) {
341→            throw new Error(`upstream image status ${response.status}`);
342→        }
343→
344→        const finalUrl = response.url || imageUrl;
345→        if (!isSafeRemoteImageUrl(finalUrl)) {
346→            throw new Error('upstream redirected to unsafe url');
347→        }
348→
349→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
350→        if (!contentType.startsWith('image/')) {
351→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
352→        }
353→        if (contentType.includes('image/svg')) {
354→            throw new Error('svg images are not used for share previews');
355→        }
356→
357→        const headerContentLength = Number(response.headers.get('content-length'));
358→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
359→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
360→        }
361→
362→        const arrayBuffer = await response.arrayBuffer();
363→        const buffer = Buffer.from(arrayBuffer);
364→
365→        if (!buffer.length) {
366→            throw new Error('upstream image is empty');
367→        }
368→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
369→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
370→        }
371→
372→        return {
373→            buffer,
374→            contentType,
375→            byteLength: buffer.length,
376→            finalUrl,
377→        };
378→    } finally {
379→        clearTimeout(timeout);
380→    }
381→};
