450→app.get('/share/post/:journalId/image', async (req, res) => {
451→    const { journalId } = req.params;
452→    const debugMode = isShareImageDebugRequest(req);
453→    const debugPayload = {
454→        ok: false,
455→        fallback: false,
456→        journalId,
457→        stage: 'start',
458→        reason: '',
459→        meta: {
460→            imageCandidateSource: null,
461→            imageCandidateRaw: null,
462→            imageCandidateResolved: null,
463→            upstreamFinalUrl: null,
464→            upstreamContentType: null,
465→            upstreamBytes: null,
466→            outputBytes: null,
467→        },
468→    };
469→
470→    const fallbackWithReason = (reason) => {
471→        debugPayload.ok = false;
472→        debugPayload.fallback = true;
473→        debugPayload.stage = 'fallback';
474→        debugPayload.reason = reason;
475→        if (debugMode) {
476→            return sendShareImageDebug(res, debugPayload);
477→        }
478→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
479→    };
480→
481→    try {
482→        const journal = await getShareJournal(journalId);
483→        debugPayload.stage = 'journal_loaded';
484→        if (!journal) {
485→            return fallbackWithReason('journal_not_found');
486→        }
487→
488→        const shareMeta = buildShareMetaFromJournal(journal);
489→        debugPayload.stage = 'candidate_extracted';
490→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
491→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
492→
493→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
494→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
495→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
496→            return fallbackWithReason(candidateEvaluation.reason);
497→        }
498→
499→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
500→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
501→            return fallbackWithReason('candidate_is_default_fallback');
502→        }
503→
504→        debugPayload.stage = 'fetching_upstream';
505→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
506→        debugPayload.stage = 'upstream_loaded';
507→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
508→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
509→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
510→
511→        debugPayload.stage = 'converting_image';
512→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
513→        debugPayload.stage = 'converted_image';
514→        debugPayload.ok = true;
515→        debugPayload.reason = 'ok';
516→        debugPayload.meta.outputBytes = ogImageBuffer.length;
517→
518→        if (debugMode) {
519→            return sendShareImageDebug(res, debugPayload);
520→        }
521→
522→        res.set('Content-Type', 'image/jpeg');
523→        res.set('Cache-Control', 'public, max-age=3600');
524→        return res.send(ogImageBuffer);
525→    } catch (err) {
526→        debugPayload.stage = 'error';
527→        debugPayload.reason = err?.message || 'unknown_error';
528→        console.error('share image route error:', err?.message || err);
529→        return fallbackWithReason(debugPayload.reason);
530→    }
531→});
