 2→    return String(value)
 3→        .toLowerCase()
 4→        .trim()
 5→        .replace(/[^a-z0-9\s-]/g, "")
 6→        .replace(/\s+/g, "-")
 7→        .replace(/-+/g, "-")
 8→        .replace(/^-|-$/g, "");
